let src_ep_ptr = pre_self_.get_thread(src_thread_ptr).endpoint_descriptors@[src_endpoint_index as int].unwrap();

// Re-state both copies of each frame-condition ensures with explicit triggers so the
// SMT solver actually has a quantifier instance keyed on the right ground term.
assert(forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr) ==>
        post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
assert(forall|p_ptr: ProcPtr|
    #![trigger post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr) ==>
        post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));

assert(forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr) ==>
        post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
assert(forall|c_ptr: ContainerPtr|
    #![trigger post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr) ==>
        post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));

assert(forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != dst_thread_ptr ==>
        pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
assert(forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != dst_thread_ptr ==>
        pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));

assert(forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != src_ep_ptr ==>
        pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
assert(forall|e_ptr: EndpointPtr|
    #![trigger post2_self_.get_endpoint(e_ptr)]
    post2_self_.endpoint_dom().contains(e_ptr) && e_ptr != src_ep_ptr ==>
        pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));

// Domain equalities transit through pre_self_.
assert(post1_self_.container_dom() =~= post2_self_.container_dom());
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());
assert(post1_self_.endpoint_dom() =~= post2_self_.endpoint_dom());

// Pointwise: procs agree on the whole pre-domain. Multi-trigger so the
// instantiation is keyed by either side's get_proc term.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr) implies
        post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
};

// Pointwise: containers agree on the whole pre-domain.
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr), post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr) implies
        post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {
    assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
};

// Threads other than dst_thread_ptr are wholly unchanged in both runs.
// The ensures uses pre_self_.get_thread(t_ptr) as trigger; reuse it here.
assert forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != dst_thread_ptr implies
        post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
    assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
    assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
};

// Endpoints other than src_ep_ptr are unchanged in both runs.
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
    pre_self_.endpoint_dom().contains(e_ptr) && e_ptr != src_ep_ptr implies
        post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {
    assert(post1_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
};

// dst_thread_ptr's endpoint_descriptors take the same updated value in both runs.
assert(post1_self_.get_thread(dst_thread_ptr).endpoint_descriptors@ =~=
    pre_self_.get_thread(dst_thread_ptr).endpoint_descriptors@.update(
        dst_endpoint_index as int, Some(src_ep_ptr)));
assert(post2_self_.get_thread(dst_thread_ptr).endpoint_descriptors@ =~=
    pre_self_.get_thread(dst_thread_ptr).endpoint_descriptors@.update(
        dst_endpoint_index as int, Some(src_ep_ptr)));
assert(post1_self_.get_thread(dst_thread_ptr).endpoint_descriptors@ =~=
    post2_self_.get_thread(dst_thread_ptr).endpoint_descriptors@);

// src_ep_ptr endpoint fields (owning_threads, queue) agree across both runs.
assert(post1_self_.get_endpoint(src_ep_ptr).owning_threads@ ==
    pre_self_.get_endpoint(src_ep_ptr).owning_threads@.insert((dst_thread_ptr, dst_endpoint_index)));
assert(post2_self_.get_endpoint(src_ep_ptr).owning_threads@ ==
    pre_self_.get_endpoint(src_ep_ptr).owning_threads@.insert((dst_thread_ptr, dst_endpoint_index)));
assert(post1_self_.get_endpoint(src_ep_ptr).owning_threads@ ==
    post2_self_.get_endpoint(src_ep_ptr).owning_threads@);

assert(post1_self_.get_endpoint(src_ep_ptr).queue ==
    pre_self_.get_endpoint(src_ep_ptr).queue);
assert(post2_self_.get_endpoint(src_ep_ptr).queue ==
    pre_self_.get_endpoint(src_ep_ptr).queue);
assert(post1_self_.get_endpoint(src_ep_ptr).queue ==
    post2_self_.get_endpoint(src_ep_ptr).queue);

// queue_state ensures reference postN_self_.get_thread(src_thread_ptr).endpoint_descriptors
// at src_endpoint_index — src_thread_ptr is unchanged in both runs (it's != dst_thread_ptr),
// so that resolves to src_ep_ptr.
assert(pre_self_.thread_dom().contains(src_thread_ptr));
assert(src_thread_ptr != dst_thread_ptr);
assert(pre_self_.get_thread(src_thread_ptr) =~= post1_self_.get_thread(src_thread_ptr));
assert(pre_self_.get_thread(src_thread_ptr) =~= post2_self_.get_thread(src_thread_ptr));
assert(post1_self_.get_thread(src_thread_ptr).endpoint_descriptors@[src_endpoint_index as int].unwrap()
    == src_ep_ptr);
assert(post2_self_.get_thread(src_thread_ptr).endpoint_descriptors@[src_endpoint_index as int].unwrap()
    == src_ep_ptr);
assert(post1_self_.get_endpoint(src_ep_ptr).queue_state ==
    pre_self_.get_endpoint(src_ep_ptr).queue_state);
assert(post2_self_.get_endpoint(src_ep_ptr).queue_state ==
    pre_self_.get_endpoint(src_ep_ptr).queue_state);
assert(post1_self_.get_endpoint(src_ep_ptr).queue_state ==
    post2_self_.get_endpoint(src_ep_ptr).queue_state);
